INSERT INTO t_repair_project_quote_invitation (
    project_id, plan_id, tenant_id, supplier_dept_id, invited_by_user_id,
    deadline, status, invitation_round, invitation_type, revision_reason
) VALUES (
    #{projectId}, #{planId}, #{tenantId}, #{supplierDeptId}, #{invitedByUserId},
    #{deadline}, #{status}, #{invitationRound}, #{invitationType}, #{revisionReason}
)

mapper.select:
SELECT 
FROM (
    SELECT DISTINCT ON (supplier_dept_id) latest.*
    FROM t_repair_project_quote_invitation latest
    WHERE latest.project_id = #{projectId}
      AND latest.plan_id = #{planId}
      AND latest.tenant_id = #{tenantId}
      AND latest.status <> 'CANCELLED'
    ORDER BY supplier_dept_id, invitation_round DESC, invitation_id DESC
) invitation
JOIN t_supplier_org_profile supplier
  ON supplier.supplier_dept_id = invitation.supplier_dept_id
ORDER BY invitation.sent_at, invitation.invitation_id

SELECT 
FROM t_repair_project_quote_invitation invitation
JOIN t_supplier_org_profile supplier
  ON supplier.supplier_dept_id = invitation.supplier_dept_id
WHERE invitation.invitation_id = #{invitationId}
  AND invitation.project_id = #{projectId}
  AND invitation.plan_id = #{planId}
  AND invitation.tenant_id = #{tenantId}
  AND invitation.supplier_dept_id = #{supplierDeptId}

SELECT EXISTS (
    SELECT 1
    FROM t_repair_project_quote_invitation
    WHERE project_id = #{projectId}
      AND plan_id = #{planId}
      AND tenant_id = #{tenantId}
      AND supplier_dept_id = #{supplierDeptId}
      AND invitation_type = 'INITIAL'
      AND status <> 'CANCELLED'
)

SELECT COALESCE(MAX(invitation_round), 0) + 1
FROM t_repair_project_quote_invitation
WHERE project_id = #{projectId}
  AND plan_id = #{planId}
  AND tenant_id = #{tenantId}
  AND supplier_dept_id = #{supplierDeptId}

mapper.update:
UPDATE t_repair_project_quote_invitation
SET status = 'SUBMITTED', responded_at = CURRENT_TIMESTAMP
WHERE invitation_id = #{invitationId}
  AND tenant_id = #{tenantId}
  AND status = 'PENDING'

mapper.select:
SELECT 
FROM t_repair_project_supplier_quote
WHERE quote_id = #{quoteId}
  AND project_id = #{projectId}
  AND plan_id = #{planId}
  AND tenant_id = #{tenantId}

SELECT 
FROM t_repair_project_supplier_quote
WHERE project_id = #{projectId}
  AND plan_id = #{planId}
  AND tenant_id = #{tenantId}
  AND supplier_dept_id = #{supplierDeptId}
ORDER BY revision_no DESC, quote_id DESC
LIMIT 1

SELECT 
FROM t_repair_project_supplier_quote
WHERE project_id = #{projectId}
  AND plan_id = #{planId}
  AND tenant_id = #{tenantId}
ORDER BY supplier_name, revision_no DESC, quote_id DESC

mapper.update:
UPDATE t_repair_project_supplier_quote
SET quote_status = 'SUPERSEDED', superseded_by_quote_id = #{supersededByQuoteId}
WHERE quote_id = #{quoteId}
  AND quote_status IN ('ACTIVE', 'REVISION_REQUESTED', 'SUPERSEDED')

mapper.select:
SELECT COUNT(DISTINCT supplier_dept_id)
FROM t_repair_project_quote_invitation
WHERE project_id = #{projectId}
  AND plan_id = #{planId}
  AND tenant_id = #{tenantId}
  AND invitation_type = 'INITIAL'
  AND status <> 'CANCELLED'

SELECT COUNT(DISTINCT supplier_dept_id)
FROM t_repair_project_supplier_quote
WHERE project_id = #{projectId}
  AND plan_id = #{planId}
  AND tenant_id = #{tenantId}
  AND quote_status = 'ACTIVE'
  AND confirmation_status IN ('ONLINE_CONFIRMED', 'OFFLINE_EVIDENCE_VERIFIED', 'CONTRACT_CONFIRMED')

